func emitForecast(cmd *cobra.Command, rows []inputRow) error {
	s, err := store.OpenWithContext(cmd.Context(), defaultDBPath("pcgs-pp-cli"))
	if err != nil {
		return fmt.Errorf("open store: %w", err)
	}
	defer s.Close()
	live, hits, planned := 0, 0, 0
	for _, r := range rows {
		if r.Err != "" || r.CertNo == "" {
			continue
		}
		planned++
		if _, err := s.Get("coin", r.CertNo); err == nil {
			hits++
		} else if err == sql.ErrNoRows {
			live++
		} else {
			return fmt.Errorf("cache probe %s: %w", r.CertNo, err)
		}
	}
	q, err := cliutil.ReadQuotaFromDB(cmd.Context(), s.DB())
	if err != nil {
		return err
	}
	pct := 0.0
	if q.Remaining > 0 {
		pct = 100.0 * float64(live) / float64(q.Remaining)
	}
	out := map[string]any{"planned": planned, "live_calls": live, "cache_hits": hits, "remaining_quota": q.Remaining, "quota_after": q.Remaining - live, "fits_today": live <= q.Remaining, "percent_of_remaining": pct}
	if err := json.NewEncoder(cmd.OutOrStdout()).Encode(out); err != nil {
		return fmt.Errorf("encode output: %w", err)
	}
	return nil
}

